import spacy

nlp = spacy.load("en_core_web_sm")

sentences = [
    "The courier damaged the package.",
    "Customers love the new packaging.",
    "The support team resolved my issue quickly.",
]

def extract_svo(raw: str) -> list[tuple]:
    text = raw.lower()  # lowercase before tokenizing
    doc = nlp(text)
    triples = []
    for token in doc:
        if token.dep_ == "ROOT" and token.pos_ == "VERB":
            verb = token.lemma_
            subjects = [
                child.text for child in token.children
                if child.dep_ in ("nsubj", "nsubjpass")
            ]
            objects = [
                child.text for child in token.children
                if child.dep_ in ("dobj", "pobj", "attr")
            ]
            for subj in subjects:
                for obj in objects:
                    triples.append((subj, verb, obj))
    return triples

for raw in sentences:
    triples = extract_svo(raw)
    print(f"Text   : {raw}")
    print(f"SVO    : {triples}")
    print()
```

spaCy's dependency parser labels arcs with `nsubj` (nominal subject), `dobj` (direct object), `ROOT` (the main verb). Text is lowercased before tokenizing so token texts in the triples are lowercase. No NLTK parser used.
